module dram_cell (  
    input wire [3:0] D,  
    input wire WE,  
    input wire CLK,  
    output reg [3:0] Q  
);  
    reg [3:0] cell_data;  

    always @(posedge CLK) begin  
        if (WE)  
            cell_data <= D;  
        else  
            Q <= cell_data;  
    end  
endmodule
